import React, { useEffect, useState } from 'react';
import axios from 'axios';
import SellerBadge from '../components/SellerBadge';

const Marketplace = () => {
  const [items, setItems] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');

  const handleBuy = async (item) => {
    const buyerId = localStorage.getItem('userId');
    
    if (!buyerId) {
      alert("Please log in to buy items.");
      return;
    }

    try {
      await axios.post('http://localhost:5000/api/transactions/buy', {
        itemId: item._id,
        buyerId: buyerId,
        sellerId: item.sellerId,
        price: item.price,
        title: item.title
      });

      alert(`Success! You bought the ${item.title}.`);
      
      // Remove the item from the local state so it disappears from the grid immediately
      setItems(items.filter(i => i._id !== item._id));
    } catch (err) {
      console.error(err);
      alert("Transaction failed.");
    }
  };

  useEffect(() => {
    const fetchItems = async () => {
      try {
        const res = await axios.get('http://localhost:5000/api/items/all');
        setItems(res.data);
      } catch (err) {
        console.error("Error fetching items", err);
      }
    };
    fetchItems();
  }, []);

  // Filter logic for Search
  const filteredItems = items.filter(item => 
    item.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.category.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div style={{ padding: '40px' }}>
      <h2>Vintage Marketplace</h2>
      
      {/* Search Bar */}
      <input 
        type="text" 
        placeholder="Search by name or category (e.g. Jackets)..." 
        style={searchStyle}
        onChange={(e) => setSearchTerm(e.target.value)}
      />

      <div style={gridStyle}>
        {filteredItems.map((item) => (
            <div key={item._id} style={cardStyle}>
                <img src={item.imageUrl} alt={item.title} style={{ width: '100%', borderRadius: '8px' }} />
                <h3>{item.title}</h3>
                <p>{item.category} - <strong>${item.price}</strong></p>
                
                <div style={{ borderTop: '1px solid #eee', paddingTop: '10px', marginTop: '10px' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
                    <small>Seller: {item.sellerEmail}</small>
                    
                    {/* Check the populated data from the backend */}
                    {item.sellerId?.isVerifiedSeller && (
                        <SellerBadge isVerified={true} />
                    )}
                    </div>
                </div>

                <button onClick={() => handleBuy(item)} style={buyButtonStyle}>
                    Buy Now
                </button>
            </div>
        ))}
      </div>
    </div>
  );
};

// Simple styles for the grid
const buyButtonStyle = {
  marginTop: '15px',
  width: '100%',
  padding: '10px',
  backgroundColor: '#2e7d32', // Green for purchase
  color: 'white',
  border: 'none',
  borderRadius: '4px',
  cursor: 'pointer',
  fontWeight: 'bold'
};
const searchStyle = { width: '100%', padding: '12px', marginBottom: '30px', borderRadius: '8px', border: '1px solid #ddd' };
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: '20px' };
const cardStyle = { border: '1px solid #eee', padding: '15px', borderRadius: '12px', boxShadow: '0 4px 6px rgba(0,0,0,0.05)' };

export default Marketplace;
